mapper.select:
SELECT count(*) FROM user_profiles u

    AND u.id = #{userId}
    AND u.email LIKE CONCAT('%', #{email}, '%')
    AND u.first_name LIKE CONCAT('%', #{firstName}, '%')
    AND u.last_name LIKE CONCAT('%', #{lastName}, '%')
    AND u.role = #{role}
    AND u.phone = #{phone}
    AND u.state_id = #{stateId}
